import{_ as e,c as o,o as d,a3 as c}from"./chunks/framework.CTM16EAR.js";const g=JSON.parse('{"title":"手势与点击实施盘点（第一步）","description":"","frontmatter":{},"headers":[],"relativePath":"dev-log/gesture-interaction-inventory.zh-CN.md","filePath":"dev-log/gesture-interaction-inventory.zh-CN.md","lastUpdated":1775185454000}'),r={name:"dev-log/gesture-interaction-inventory.zh-CN.md"};function n(a,t,s,l,i,h){return d(),o("div",null,t[0]||(t[0]=[c('<h1 id="手势与点击实施盘点-第一步" tabindex="-1">手势与点击实施盘点（第一步） <a class="header-anchor" href="#手势与点击实施盘点-第一步" aria-label="Permalink to &quot;手势与点击实施盘点（第一步）&quot;">​</a></h1><p>本文档只描述现状，不定义目标行为；Composable 抽取与跨平台语义统一见后续步骤。</p><h2 id="_1-模式代号-与计划一致" tabindex="-1">1. 模式代号（与计划一致） <a class="header-anchor" href="#_1-模式代号-与计划一致" aria-label="Permalink to &quot;1. 模式代号（与计划一致）&quot;">​</a></h2><ul><li><strong>A</strong>：纯鼠标/语义化点击——<code>@click</code> / <code>@dblclick</code>（无自定义触摸分支）。</li><li><strong>B</strong>：Pointer 按下 + 移动阈值 → 拖拽或单击分流（与双击/长按体系独立）。</li><li><strong>C</strong>：触摸：<strong>延迟单击</strong>（定时器）+ <strong>两次点击间隔</strong>判定双击——用于 DayTodo 意图列、DaySchedule 标题/地点。</li><li><strong>D</strong>：触摸：<strong>第一次抬起即执行「单击」语义</strong> + <strong>间隔内第二次抬起</strong>为双击——用于 ActivitySection 标题行。</li><li><strong>E</strong>：<code>useLongPress</code>——定时长按（默认 600ms）；当前仅年视图日格与 composable 定义相关。</li><li><strong>F</strong>：在元素或 <code>document</code> 上使用 <code>preventDefault</code>、<code>stop/stopPropagation</code>、capture 监听等，改变浏览器/Naive UI 默认点击或滚动链。</li></ul><p><strong>Naive UI</strong>：未改组件库源码；「改写」均来自业务层事件与全局 <code>touchHandler</code>。</p><h2 id="_2-语义与参数总表" tabindex="-1">2. 语义与参数总表 <a class="header-anchor" href="#_2-语义与参数总表" aria-label="Permalink to &quot;2. 语义与参数总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域 / 组件</th><th>桌面：单击</th><th>桌面：双击</th><th>移动：单击</th><th>移动：双击 / 长按</th><th>关键毫秒</th></tr></thead><tbody><tr><td><strong>YearPlanner</strong> 日格（当月）</td><td><code>handleDayClick</code>：设应用日期、选中任务</td><td><code>handleDayDblClick</code>：emit 日视图</td><td><code>touchend</code> 始终 <code>handleDayClick</code>（与触摸路径并行）</td><td><code>touchstart</code> + <code>useLongPress(600)</code>：<code>onLongPress</code> emit 日视图</td><td>长按 <strong>600</strong>；<code>useLongPress</code> 结束触摸后内部重置延迟 <strong>300</strong></td></tr><tr><td><strong>DayTodo</strong> 意图列</td><td>子格 <code>click</code> → <code>handleRowClick</code>；<code>dblclick</code> → <code>startEditing(title)</code></td><td>同左</td><td><code>isMobile</code>：<code>touchstart/end/cancel</code>；首击 <strong>300ms 后</strong> <code>handleRowClick</code>；300ms 内第二击 → <code>startEditing(title)</code></td><td>无独立长按</td><td><strong>300</strong>（<code>DOUBLE_CLICK_DELAY</code>）</td></tr><tr><td><strong>DaySchedule</strong> 意图列</td><td>同 DayTodo 模式</td><td>同左</td><td>同 DayTodo（<code>handleTitleTouch*</code>）</td><td>无独立长按</td><td><strong>300</strong></td></tr><tr><td><strong>DaySchedule</strong> 地点列</td><td>同左（<code>location</code> 字段）</td><td>同左</td><td><code>handleLocationTouch*</code>（同 C 模式）</td><td>无</td><td><strong>300</strong></td></tr><tr><td><strong>ActivitySection</strong> 标题区</td><td>输入聚焦等（见组件内 <code>handleTitleInputFocus</code>）</td><td>桌面另有番茄格等 mousedown 双击逻辑</td><td><strong>第一次 <code>touchend</code> 即 <code>handleFocusRow</code></strong>；300ms 内第二次 → <code>titleEditAllowed</code> + 聚焦标题输入</td><td>无与年视图相同的长按</td><td><strong>300</strong></td></tr><tr><td><strong>useLongPress</strong></td><td>—</td><td>—</td><td><code>onLongPressStart</code> 接受 <code>TouchEvent | MouseEvent</code></td><td>定时触发 <code>onLongPress</code></td><td>默认 <strong>600</strong>；触摸结束重置 <strong>300</strong></td></tr></tbody></table><h2 id="_3-主文件-模板事件-↔-脚本处理-行号以当前仓库为准" tabindex="-1">3. 主文件：模板事件 ↔ 脚本处理（行号以当前仓库为准） <a class="header-anchor" href="#_3-主文件-模板事件-↔-脚本处理-行号以当前仓库为准" aria-label="Permalink to &quot;3. 主文件：模板事件 ↔ 脚本处理（行号以当前仓库为准）&quot;">​</a></h2><h3 id="_3-1-yearplanner-vue" tabindex="-1">3.1 YearPlanner.vue <a class="header-anchor" href="#_3-1-yearplanner-vue" aria-label="Permalink to &quot;3.1 YearPlanner.vue&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模板位置</th><th>绑定</th><th>处理函数 / 说明</th><th>平台</th></tr></thead><tbody><tr><td>L6</td><td><code>@click</code></td><td><code>handleMonthTitleClick</code></td><td>全平台</td></tr><tr><td>L15</td><td><code>@click</code></td><td><code>handleWeekClick</code></td><td>全平台</td></tr><tr><td>L29–33</td><td><code>@click</code> / <code>@dblclick.stop</code> / <code>@touchstart.stop</code> / <code>@touchend.stop</code> / <code>@touchcancel.stop</code></td><td><code>handleDayClick</code> / <code>handleDayDblClick</code> / <code>handleDayTouchStart</code> / <code>handleDayTouchEnd</code> / <code>handleDayTouchCancel</code>（仅 <code>day &amp;&amp; day.isCurrentMonth</code>）</td><td>触摸分支仅移动端生效</td></tr></tbody></table><table tabindex="0"><thead><tr><th>脚本位置</th><th>内容</th></tr></thead><tbody><tr><td>L56–57</td><td><code>import useLongPress</code></td></tr><tr><td>L86</td><td><code>dayLongPressHandler</code>：<code>ref&lt;ReturnType&lt;typeof useLongPress&gt; | null&gt;</code>，<strong>懒创建单例</strong></td></tr><tr><td>L217–253</td><td><code>handleDayClick</code>、<code>handleDayDblClick</code>、<code>handleDayTouchStart</code>（<code>preventDefault</code> + 首次创建 <code>useLongPress({ delay: 600, onLongPress })</code>）、<code>handleDayTouchEnd</code>（<code>onLongPressEnd</code> 后 <strong>仍</strong> <code>handleDayClick</code>）、<code>handleDayTouchCancel</code></td></tr></tbody></table><h3 id="_3-2-daytodo-vue" tabindex="-1">3.2 <a href="https://github.com/Xeonilian/pomotention/blob/main/src/components/DayPlanner/DayTodo.vue" target="_blank" rel="noreferrer"><code>DayTodo.vue</code></a> <a class="header-anchor" href="#_3-2-daytodo-vue" aria-label="Permalink to &quot;3.2 [`DayTodo.vue`](https://github.com/Xeonilian/pomotention/blob/main/src/components/DayPlanner/DayTodo.vue)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模板位置</th><th>绑定</th><th>说明</th></tr></thead><tbody><tr><td>L132</td><td><code>tr</code>：<code>@click.stop</code></td><td><code>handleRowClick</code></td></tr><tr><td>L132–263</td><td>各子格大量 <code>@click.stop</code></td><td>开始/结束时间单击编辑、排序 popover、意图列等</td></tr><tr><td>L240–246</td><td>意图列 <code>col-intent</code></td><td><code>@click.stop</code> → <code>handleRowClick</code>；<code>@dblclick.stop</code> → <code>startEditing(title)</code>；<code>@touchstart</code> / <code>@touchend</code> / <code>@touchcancel</code> → <code>handleTitleTouch*</code></td></tr><tr><td>L548–558</td><td><code>watch(rankPopoverTodoId)</code></td><td><code>document</code> <strong>capture</strong>：<code>mousedown</code> + <code>touchstart</code>（passive）→ <code>handleRankPopoverClickOutside</code>（<strong>F</strong>）</td></tr></tbody></table><table tabindex="0"><thead><tr><th>脚本位置</th><th>内容</th></tr></thead><tbody><tr><td>L519–521</td><td><code>DOUBLE_CLICK_DELAY = 300</code>，<code>titleTapTimers</code>，<code>titleLastTapInfo</code></td></tr><tr><td>L954–970</td><td><code>handleRowClick</code></td></tr><tr><td>L980–1009</td><td><code>startEditing</code></td></tr><tr><td>L1273–1305</td><td><code>handleTitleTouchStart</code> / <code>End</code> / <code>Cancel</code>（<code>isMobile</code> 卫语句；<strong>C</strong>）</td></tr></tbody></table><h3 id="_3-3-dayschedule-vue" tabindex="-1">3.3 <a href="https://github.com/Xeonilian/pomotention/blob/main/src/components/DayPlanner/DaySchedule.vue" target="_blank" rel="noreferrer"><code>DaySchedule.vue</code></a> <a class="header-anchor" href="#_3-3-dayschedule-vue" aria-label="Permalink to &quot;3.3 [`DaySchedule.vue`](https://github.com/Xeonilian/pomotention/blob/main/src/components/DayPlanner/DaySchedule.vue)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模板位置</th><th>绑定</th><th>说明</th></tr></thead><tbody><tr><td>L101–111</td><td><code>tr</code>：<code>@click.stop</code></td><td><code>handleRowClick(schedule)</code></td></tr><tr><td>L199–208</td><td>意图列</td><td>与 DayTodo 对齐：<code>handleRowClick</code> + <code>dblclick</code> + <code>handleTitleTouch*</code></td></tr><tr><td>L238–244</td><td>地点列</td><td><code>handleRowClick</code> + <code>dblclick</code> + <code>handleLocationTouch*</code></td></tr></tbody></table><table tabindex="0"><thead><tr><th>脚本位置</th><th>内容</th></tr></thead><tbody><tr><td>L361</td><td><code>DOUBLE_CLICK_DELAY = 300</code></td></tr><tr><td>L698–777</td><td><code>clearTitleTapTimer</code>、<code>handleTitleTouch*</code>、<code>handleLocationTouch*</code>（<strong>C</strong>；<code>isMobile</code>）</td></tr></tbody></table><h3 id="_3-4-activitysection-vue" tabindex="-1">3.4 <a href="https://github.com/Xeonilian/pomotention/blob/main/src/components/ActivitySheet/ActivitySection.vue" target="_blank" rel="noreferrer"><code>ActivitySection.vue</code></a> <a class="header-anchor" href="#_3-4-activitysection-vue" aria-label="Permalink to &quot;3.4 [`ActivitySection.vue`](https://github.com/Xeonilian/pomotention/blob/main/src/components/ActivitySheet/ActivitySection.vue)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模板位置</th><th>绑定</th><th>说明</th></tr></thead><tbody><tr><td>L25</td><td>筛选按钮</td><td><code>@pointerdown.stop</code> <code>@mousedown.prevent.stop</code> <code>@touchstart.stop</code>（避免触发异常；<strong>F</strong>）</td></tr><tr><td>L79</td><td><code>@click.stop</code></td><td><code>handleCollapseParent</code></td></tr><tr><td>L93–95</td><td>标题行触摸</td><td><code>handleTitleTouchStart</code> / <code>End</code> / <code>Cancel</code>（<strong>D</strong>；<code>isMobile</code>）</td></tr><tr><td>L107–109</td><td>拖拽柄</td><td><code>@pointerdown.prevent.stop=&quot;onDragStart&quot;</code> + <code>@mousedown.prevent.stop</code> + <code>@touchstart.stop</code>（<strong>B</strong>）</td></tr><tr><td>L185–190</td><td>标签图标等</td><td><code>click</code> + <code>pointerdown/mousedown/touch</code> stop，避免与拖拽/标题吞事件混淆</td></tr><tr><td>L257–260</td><td>番茄输入</td><td><code>mousedown</code> / <code>touchstart</code> / <code>touchend</code> / <code>touchcancel</code> → <code>handlePomoInput*</code>（桌面双击 + 移动触摸，<strong>混合</strong>）</td></tr></tbody></table><table tabindex="0"><thead><tr><th>脚本位置</th><th>内容</th></tr></thead><tbody><tr><td>L488–519</td><td><code>DOUBLE_CLICK_DELAY</code>、<code>pomoDoubleClickTimers</code>、<code>clickDragState</code>、<code>DRAG_THRESHOLD</code>（<strong>B</strong>）</td></tr><tr><td>L633–669</td><td><code>handleTitleTouchStart</code> / <code>End</code> / <code>Cancel</code>（<strong>D</strong>）</td></tr><tr><td>L705–743</td><td><code>onDragStart</code>：<code>hasChildren</code> 时进入阈值检测，否则 <code>dragHandler.startDrag</code></td></tr></tbody></table><h3 id="_3-5-uselongpress-ts" tabindex="-1">3.5 <a href="https://github.com/Xeonilian/pomotention/blob/main/src/composables/useLongPress.ts" target="_blank" rel="noreferrer"><code>useLongPress.ts</code></a> <a class="header-anchor" href="#_3-5-uselongpress-ts" aria-label="Permalink to &quot;3.5 [`useLongPress.ts`](https://github.com/Xeonilian/pomotention/blob/main/src/composables/useLongPress.ts)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>行号</th><th>行为</th></tr></thead><tbody><tr><td>L4–7</td><td>可选 <code>delay</code>（默认 600）、<code>onLongPress</code></td></tr><tr><td>L18–31</td><td><code>onLongPressStart</code>：按 <code>touchstart</code> 设 <code>isTouch</code>；<code>setTimeout</code> 触发回调</td></tr><tr><td>L35–47</td><td><code>onLongPressEnd</code>：清定时器；触摸时延迟 300ms 再重置内部状态</td></tr><tr><td>L51–57</td><td><code>onLongPressCancel</code>：立即清状态</td></tr></tbody></table><p><strong>调用方注意</strong>：返回的 <code>longPressTriggered</code> 未被 YearPlanner 用于阻止 <code>touchend</code> 上的 <code>handleDayClick</code>。</p><h2 id="_4-pointer-拖拽-调整尺寸-非长按·非双击-c-d" tabindex="-1">4. Pointer / 拖拽 / 调整尺寸（非长按·非双击 C/D） <a class="header-anchor" href="#_4-pointer-拖拽-调整尺寸-非长按·非双击-c-d" aria-label="Permalink to &quot;4. Pointer / 拖拽 / 调整尺寸（非长按·非双击 C/D）&quot;">​</a></h2><p>以下与「表格标题双击 / 年视图长按」体系无关，仅作并列索引，避免混谈。</p><table tabindex="0"><thead><tr><th>文件</th><th>作用（一行）</th></tr></thead><tbody><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/composables/useDraggable.ts" target="_blank" rel="noreferrer"><code>useDraggable.ts</code></a></td><td><code>@pointerdown</code> → <code>handleDragStart</code>；<code>preventDefault</code> + 阈值 5px 拖拽（迷你浮窗等）</td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/views/MainLayout.vue" target="_blank" rel="noreferrer"><code>MainLayout.vue</code></a> L106</td><td>布局上拖拽柄：<code>@pointerdown=&quot;handleDragStart&quot;</code>，使用 <code>useDraggable(5)</code></td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/composables/useActivityDrag.ts" target="_blank" rel="noreferrer"><code>useActivityDrag.ts</code></a></td><td>Activity 列表拖拽；模板约定 <code>@pointerdown=&quot;startDrag($event, item)&quot;</code></td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/composables/useResize.ts" target="_blank" rel="noreferrer"><code>useResize.ts</code></a></td><td><code>startResize</code>：分隔条拖动调整高度/宽度</td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/views/HomeView.vue" target="_blank" rel="noreferrer"><code>HomeView.vue</code></a> L19 / L280 / L295</td><td>左/中/右分隔：<code>@pointerdown</code> → <code>startLeftResize</code> / <code>startVerticalResize</code> / <code>startRightResize</code></td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/views/SearchView.vue" target="_blank" rel="noreferrer"><code>SearchView.vue</code></a> L114</td><td>非移动：<code>resize-handle-horizontal</code> + <code>touch-action: none</code> + <code>@pointerdown=&quot;resizeSearch.startResize&quot;</code></td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/components/TimeTable/TimeBlocks.vue" target="_blank" rel="noreferrer"><code>TimeBlocks.vue</code></a> L53 / L70</td><td>Todo 段：<code>@pointerdown=&quot;enhancedHandlePointerDown&quot;</code>（逻辑在 <code>useTimeBlocks</code>：选中/拖拽时间条等）</td></tr><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/components/PomotentionTimer/PomodoroTimer.vue" target="_blank" rel="noreferrer"><code>PomodoroTimer.vue</code></a> L4</td><td>可编辑文案：<code>@click.stop</code> + <code>@pointerdown.stop</code>，避免父级抢事件</td></tr></tbody></table><h2 id="_5-全局触摸辅助" tabindex="-1">5. 全局触摸辅助 <a class="header-anchor" href="#_5-全局触摸辅助" aria-label="Permalink to &quot;5. 全局触摸辅助&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>作用</th></tr></thead><tbody><tr><td><a href="https://github.com/Xeonilian/pomotention/blob/main/src/core/utils/touchHandler.ts" target="_blank" rel="noreferrer"><code>touchHandler.ts</code></a></td><td><code>document</code>：<code>touchstart</code>/<code>touchmove</code>/<code>touchend</code>；非交互元素横向快滑时 <code>touchmove</code> 上 <code>preventDefault</code>（与 <strong>F</strong> 同类但全局）</td></tr></tbody></table><h2 id="_6-第三步之前的差异清单-backlog" tabindex="-1">6. 第三步之前的差异清单（Backlog） <a class="header-anchor" href="#_6-第三步之前的差异清单-backlog" aria-label="Permalink to &quot;6. 第三步之前的差异清单（Backlog）&quot;">​</a></h2><ol><li><p><strong>C vs D（标题「单击」时机）</strong><br> DayTodo / DaySchedule：移动上单次点击意图（或地点）<strong>晚 300ms</strong> 才等价 <code>handleRowClick</code>。<br> ActivitySection：标题 <strong>第一次 <code>touchend</code> 立即</strong> <code>handleFocusRow</code>。<br> → 用户在手心切换两处时体感不一致。</p></li><li><p><strong>YearPlanner <code>handleDayTouchEnd</code></strong><br> 每次 <code>touchend</code> 在 <code>onLongPressEnd</code> 之后 <strong>始终</strong> 调用 <code>handleDayClick</code>。若已触发长按，<code>onLongPress</code> 已 emit 日视图，仍会再选中日/任务。是否预期需在第三步与 PM/自测确认。</p></li><li><p><strong><code>useLongPress</code> 实例化方式</strong><br> YearPlanner 在首次触摸日格时 <strong>创建一次</strong> composable 并复用；回调闭包捕获的 <code>dayStartTs</code> 为<strong>首次创建时</strong>的那一天。若长期不销毁组件、用户改点其它日期，需核对 <code>onLongPress</code> 是否仍针对<strong>当前手指按下</strong>的那一天（当前实现仅在 <code>handler</code> 为 null 时 new，<strong>不会</strong>按每次 <code>touchstart</code> 的 <code>dayStartTs</code> 更新）。→ 第三步应改为每次按下更新回调或每格独立 handler。</p></li><li><p><strong><code>longPressTriggered</code> 未消费</strong><br><code>touchend</code> 未根据「是否刚触发长按」跳过或合并 <code>handleDayClick</code>，与第 2 条相关。</p></li><li><p><strong>常量分散</strong><br><code>DOUBLE_CLICK_DELAY = 300</code> 出现在 DayTodo、DaySchedule、ActivitySection；长按 600 在 YearPlanner 调用与 <code>useLongPress</code> 默认中重复出现。第三步可收敛配置。</p></li></ol><hr><p><em>文档版本：与仓库第一步梳理同步；行号若因编辑漂移请以 IDE 为准。</em></p>',32)]))}const b=e(r,[["render",n]]);export{g as __pageData,b as default};
